import{_ as a,c as s,o as n,a as e,b as o}from"./app.426dd711.js";const D=JSON.parse('{"title":"Cliente en su Sitio (On-Site Customer)","description":"","frontmatter":{},"headers":[],"relativePath":"practices/on-site-customer.md"}'),r={name:"practices/on-site-customer.md"},t=e("h1",{id:"cliente-en-su-sitio-on-site-customer",tabindex:"-1"},[o("Cliente en su Sitio "),e("em",null,"(On-Site Customer)"),o(),e("a",{class:"header-anchor",href:"#cliente-en-su-sitio-on-site-customer","aria-hidden":"true"},"#")],-1),i=e("p",null,"Las funcionalidades que debe cumplir el proyecto son dictadas por el Due\xF1o del Producto (usuario principal). Estas funcionalidades puede que no queden totalmente claras desde un principio. El desarrollo \xE1gil propone, entonces, que el propio usuario se involucre en la producci\xF3n del software desde sus posibilidades.",-1),l=e("blockquote",null,[e("p",null,"El Equipo de Desarrollo deber\xE1 estar en continua comunicaci\xF3n con el Due\xF1o del Producto que deber\xE1 aclarar en la medida de lo posible los requerimientos que necesitar\xE1 utilizar. Se requiere que el Due\xF1o del Producto est\xE9 dispuesto a participar activamente en el proyecto, contando con la disponibilidad suficiente y necesaria, para interactuar con el equipo en todas las fases del proyecto.")],-1),c=e("p",null,"Es recomendable contar con m\xE1s de una persona (por parte del Due\xF1o del Producto), asignada a trabajar de forma permanente con el equipo. Las personas asignadas por el Due\xF1o del Producto, deben ser: Conocedores expertos de lo que se pretende producir. En lo posible, se pretende que sean usuarios reales del software, personas que cuenten con la informaci\xF3n suficiente sobre la aplicaci\xF3n y los objetivos del negocio, a fin de poder actuar con autoridad en la toma de decisiones. Por lo tanto, siempre habr\xE1 un usuario del sistema que sea accesible por los miembros del equipo de trabajo. El Due\xF1o del Producto debe estar f\xEDsicamente presente en las ceremonias de Planificaci\xF3n y Revisi\xF3n, y opcionalmente, en las Aperturas y de Retrospectiva.",-1),d=e("blockquote",null,[e("p",null,"La comunicaci\xF3n cara a cara con el usuario es fundamental, ya que a partir de \xE9sta, el equipo avanzar\xE1 m\xE1s r\xE1pidamente en el proyecto, puesto que: Despejar\xE1 todas sus dudas sobre el proyecto, con el usuario y en el momento que \xE9stas surjan. Se establecer\xE1n las prioridades a desarrollar, en tiempo real, as\xED como la resoluci\xF3n de conflictos. De esta forma se soluciona o al menos se facilita la compresi\xF3n de las funcionalidad que en ciertos casos suele ser la etapa mas dif\xEDcil y mas lenta del desarrollo del proyecto.")],-1),u=[t,i,l,c,d];function p(m,f,q,b,_,h){return n(),s("div",null,u)}const P=a(r,[["render",p]]);export{D as __pageData,P as default};
